/* ==========================================================================
   Shared behaviour: language toggle, grid rendering, detail rendering
   ========================================================================== */

/* ---- ENG/KOR toggle — manual bilingual text, no external translation service.
   Static text: give an element data-ko="..." (or data-ko-html/data-en-html for
   markup with <br> etc). Dynamic list/detail data: use pickText() below, which
   reads titleEn (etc.) from data.js entries. Preference persists in
   localStorage and the page reloads so every render (static + dynamic) picks
   up the new language from the start, with no flash. ---- */
function currentLang() {
  return localStorage.getItem("jb-lang") || "ko";
}

function pickText(item, koField, enField) {
  if (currentLang() === "en" && item[enField]) return item[enField];
  return item[koField];
}

function pickTags(item) {
  if (currentLang() === "en" && item.tagsEn) return item.tagsEn;
  return item.tags || [];
}

function applyLanguage(lang) {
  document.documentElement.lang = lang;
  document.querySelectorAll("[data-ko]").forEach((el) => {
    const value = lang === "en" ? el.dataset.en : el.dataset.ko;
    if (value !== undefined) el.textContent = value;
  });
  document.querySelectorAll("[data-ko-html]").forEach((el) => {
    const value = lang === "en" ? el.dataset.enHtml : el.dataset.koHtml;
    if (value !== undefined) el.innerHTML = value;
  });
}

function setSiteLanguage(lang) {
  localStorage.setItem("jb-lang", lang);
  location.reload();
}

function initLangToggle() {
  const saved = currentLang();
  applyLanguage(saved);
  document.querySelectorAll(".lang-toggle").forEach((toggle) => {
    const enBtn = toggle.querySelector('[data-lang="en"]');
    const koBtn = toggle.querySelector('[data-lang="ko"]');
    if (enBtn) enBtn.addEventListener("click", () => setSiteLanguage("en"));
    if (koBtn) koBtn.addEventListener("click", () => setSiteLanguage("ko"));
    if (enBtn && koBtn) {
      enBtn.classList.toggle("is-active", saved === "en");
      koBtn.classList.toggle("is-active", saved === "ko");
    }
  });
}

/* ---- real-image support -----------------------------------------------
   Each item's `folder` field points at a subfolder of 이미지/ (already set
   up on disk: 이미지/BOOK, 이미지/AND MORE, 이미지/NEWS, ...). Drop a file
   named after the item's slug (e.g. 이미지/BOOK/sand-city.jpg) and it will
   be picked up automatically — no code changes needed. Until a file exists,
   the colored placeholder block below shows instead. */
const IMG_EXTENSIONS = ["jpg", "jpeg", "png", "webp"];

function imageCandidates(folder, filename) {
  const encodedFolder = folder.split("/").map(encodeURIComponent).join("/");
  return IMG_EXTENSIONS.map((ext) => "이미지/" + encodedFolder + "/" + encodeURIComponent(filename) + "." + ext);
}

function handleImgFallback(img) {
  const candidates = JSON.parse(img.dataset.candidates);
  const next = parseInt(img.dataset.i, 10) + 1;
  if (next < candidates.length) {
    img.dataset.i = String(next);
    img.src = candidates[next];
  } else {
    img.style.display = "none";
    // no real photo exists yet — fall back to the plain colored swatch
    const block = img.closest(".cover-block");
    if (block) block.classList.remove("has-image");
  }
}

function realImageTag(folder, filename) {
  const candidates = imageCandidates(folder, filename);
  return (
    '<img src="' + candidates[0] + '" alt="" loading="lazy" draggable="false" ' +
    "data-candidates='" + JSON.stringify(candidates) + "' data-i=\"0\" " +
    'onerror="handleImgFallback(this)">'
  );
}

/* ---- cover placeholder builder ---- */
function coverBlockHTML(item) {
  const hasImage = Boolean(item.folder);
  const image = hasImage ? realImageTag(item.folder, item.image || item.slug) : "";
  return (
    '<div class="cover-block' + (hasImage ? " has-image" : "") + '" style="--c:' + item.color + '">' +
    image +
    "</div>"
  );
}

/* ---- home page collage — one scattered, draggable thumbnail per BOOKS entry
   (readymag.com/designs/greennation style). Clicking (without dragging) opens
   that book's detail page. ---- */
function randomBetween(min, max) {
  return min + Math.random() * (max - min);
}

/* neat two-row starting layout shown only on a visitor's very first desktop
   visit (fractions of the available left/top space); every reload after
   that goes back to the free random scatter. */
const FIRST_VISIT_LAYOUT = [
  { left: 0.00, top: 0.06, rotate: -4 },
  { left: 0.20, top: 0.02, rotate: 3 },
  { left: 0.40, top: 0.08, rotate: -2 },
  { left: 0.60, top: 0.00, rotate: 4 },
  { left: 0.80, top: 0.05, rotate: -3 },
  { left: 1.00, top: 0.10, rotate: 5 },
  { left: 0.05, top: 0.55, rotate: 4 },
  { left: 0.28, top: 0.60, rotate: -3 },
  { left: 0.50, top: 0.52, rotate: 2 },
  { left: 0.72, top: 0.58, rotate: -4 },
  { left: 0.92, top: 0.54, rotate: 3 }
];

function renderHomeBookImages(containerId) {
  const container = document.getElementById(containerId);
  if (!container) return;

  const homeBooks = BOOKS.filter((book) => !book.hideFromHome);

  // uniform size for every item, matched to "to say I love you.png" (790 x 1242px)
  const ITEM_WIDTH = 275;
  const ITEM_HEIGHT = 433;
  const ASPECT = ITEM_HEIGHT / ITEM_WIDTH;

  // on mobile, start as a neat 2-column list instead of a random scatter —
  // dragging still works exactly the same afterwards
  const mobile = window.matchMedia("(max-width: 640px)").matches;
  const gap = 16;
  const colWidth = mobile ? (container.clientWidth - gap * 3) / 2 : 0;
  const colHeight = mobile ? colWidth * ASPECT : 0;

  const isFirstVisit = !localStorage.getItem("jb-home-visited");
  localStorage.setItem("jb-home-visited", "1");

  const stage = container.closest(".hero-stage");
  if (mobile) {
    const rows = Math.ceil(homeBooks.length / 2);
    const neededHeight = rows * (colHeight + gap) + gap;
    container.style.height = neededHeight + "px";
    if (stage) stage.style.minHeight = neededHeight + "px";
  } else {
    container.style.height = "";
    if (stage) stage.style.minHeight = "";
  }

  // desktop: scatter within the container's actual measured size, in pixels,
  // so items always land fully inside it — no overflow, no page scroll
  const maxLeft = Math.max(0, container.clientWidth - ITEM_WIDTH);
  const maxTop = Math.max(0, container.clientHeight - ITEM_HEIGHT);

  container.innerHTML = homeBooks.map((book, i) => {
    let style;
    if (mobile) {
      const col = i % 2;
      const row = Math.floor(i / 2);
      const left = gap + col * (colWidth + gap);
      const top = gap + row * (colHeight + gap);
      style =
        "left:" + left + "px; top:" + top + "px; " +
        "width:" + Math.round(colWidth) + "px; height:" + Math.round(colHeight) + "px; " +
        "transform: rotate(0deg); z-index:" + (i + 1) + ";";
    } else if (isFirstVisit && FIRST_VISIT_LAYOUT[i]) {
      const pos = FIRST_VISIT_LAYOUT[i];
      const left = pos.left * maxLeft;
      const top = pos.top * maxTop;
      style =
        "left:" + left + "px; top:" + top + "px; " +
        "width:" + ITEM_WIDTH + "px; height:" + ITEM_HEIGHT + "px; " +
        "transform: rotate(" + pos.rotate + "deg); z-index:" + (i + 1) + ";";
    } else {
      const left = randomBetween(0, maxLeft);
      const top = randomBetween(0, maxTop);
      const rotate = randomBetween(-9, 9).toFixed(1);
      style =
        "left:" + left + "px; top:" + top + "px; " +
        "width:" + ITEM_WIDTH + "px; height:" + ITEM_HEIGHT + "px; " +
        "transform: rotate(" + rotate + "deg); z-index:" + (i + 1) + ";";
    }
    return (
      '<a class="drag-item" href="book-detail.html?slug=' + book.slug + '" draggable="false" style="' + style + '">' +
      realImageTag(book.folder, book.image || book.slug) +
      "</a>"
    );
  }).join("");

  container.querySelectorAll(".drag-item").forEach((el) => makeDraggable(el, container));
}

/* click-and-drag to reposition an absolutely-positioned element within its container */
function makeDraggable(el, container) {
  let startX = 0;
  let startY = 0;
  let originLeft = 0;
  let originTop = 0;
  let dragging = false;
  let moved = false;

  el.addEventListener("pointerdown", (e) => {
    dragging = true;
    moved = false;
    el.classList.add("dragging");
    el.setPointerCapture(e.pointerId);
    startX = e.clientX;
    startY = e.clientY;
    const elRect = el.getBoundingClientRect();
    const containerRect = container.getBoundingClientRect();
    originLeft = elRect.left - containerRect.left;
    originTop = elRect.top - containerRect.top;
    el.style.left = originLeft + "px";
    el.style.top = originTop + "px";
  });

  el.addEventListener("pointermove", (e) => {
    if (!dragging) return;
    const dx = e.clientX - startX;
    const dy = e.clientY - startY;
    if (Math.abs(dx) > 4 || Math.abs(dy) > 4) moved = true;
    el.style.left = originLeft + dx + "px";
    el.style.top = originTop + dy + "px";
  });

  const stopDragging = (e) => {
    if (!dragging) return;
    dragging = false;
    el.classList.remove("dragging");
  };
  el.addEventListener("pointerup", stopDragging);
  el.addEventListener("pointercancel", stopDragging);

  // if this item is a link (home collage), only navigate on a real tap —
  // a drag that actually moved the image shouldn't also open its page
  el.addEventListener("click", (e) => {
    if (moved) e.preventDefault();
  });
}

/* ---- BOOK / AND MORE grid list pages ---- */
function renderCardGrid(containerId, items, hrefBuilder) {
  const el = document.getElementById(containerId);
  if (!el) return;
  el.innerHTML = items
    .map((item) => {
      return (
        '<a class="card" href="' + hrefBuilder(item) + '">' +
        '<div class="card-cover">' + coverBlockHTML(item) + "</div>" +
        "<h3>" + pickText(item, "title", "titleEn") + "</h3>" +
        '<div class="card-desc">' + pickText(item, "summary", "summaryEn") + "</div>" +
        '<div class="tag-row">' +
        pickTags(item).map((t) => '<div class="tag">#' + t + "</div>").join("") +
        "</div>" +
        "</a>"
      );
    })
    .join("");
}

/* ---- NEWS list page (sidebar + rows) ---- */
function renderNewsList(containerId, items, hrefBuilder) {
  const el = document.getElementById(containerId);
  if (!el) return;
  el.innerHTML = items
    .map(
      (item) =>
        '<a class="news-row" href="' + hrefBuilder(item) + '">' +
        '<div class="news-cover">' + coverBlockHTML(item) + "</div>" +
        '<div class="news-text">' +
        '<div class="news-date">' + item.date + "</div>" +
        "<h3>" + pickText(item, "title", "titleEn") + "</h3>" +
        '<div class="news-desc">' + pickText(item, "summary", "summaryEn") + "</div>" +
        "</div>" +
        "</a>"
    )
    .join("");
}

/* ---- NEWS list page (simple dated log — external link if the item has one,
   plain unlinked row otherwise) ---- */
function renderNewsRows(containerId, items) {
  const el = document.getElementById(containerId);
  if (!el) return;
  el.innerHTML = items
    .map((item) => {
      const inner =
        '<div class="news-row-date">' + item.date + "</div>" +
        '<div class="news-row-title">' + pickText(item, "title", "titleEn") + "</div>";
      if (item.link) {
        return (
          '<a class="news-row-simple news-row-external" href="' + item.link + '" target="_blank" rel="noopener noreferrer">' +
          inner +
          "</a>"
        );
      }
      if (item.slug) {
        return '<a class="news-row-simple" href="news-detail.html?slug=' + item.slug + '">' + inner + "</a>";
      }
      return '<div class="news-row-simple">' + inner + "</div>";
    })
    .join("");
}

/* ---- simple page-number pagination (?page=N in the URL, 10 items per page) ---- */
function renderNewsPagination(containerId, totalItems, pageSize, currentPage) {
  const el = document.getElementById(containerId);
  if (!el) return;
  const totalPages = Math.max(1, Math.ceil(totalItems / pageSize));
  el.innerHTML = Array.from({ length: totalPages }, (_, i) => i + 1)
    .map((n) =>
      n === currentPage
        ? '<span class="news-page current">' + n + "</span>"
        : '<a class="news-page" href="news.html?page=' + n + '">' + n + "</a>"
    )
    .join("");
}

/* ---- query param helper ---- */
function getSlugFromQuery() {
  return new URLSearchParams(location.search).get("slug");
}

function findBySlug(list, slug) {
  return list.find((i) => i.slug === slug) || list[0];
}

/* ---- generic detail page renderer ----
   fields: { kicker, title, meta, synopsisTitle, synopsis, body2Title, body2, tags } */
function renderDetail(item, fields) {
  const set = (id, value, html) => {
    const el = document.getElementById(id);
    if (!el) return;
    if (html) el.innerHTML = value;
    else el.textContent = value;
  };

  set("detail-cover", coverBlockHTML(item), true);
  set("detail-kicker", fields.kicker || "");
  set("detail-title", pickText(item, "title", "titleEn"));
  set("detail-meta", fields.meta || "");
  set("synopsis-title", pickText(item, "synopsisTitle", "synopsisTitleEn") || "줄거리");
  set("synopsis-text", pickText(item, "synopsis", "synopsisEn") || "");
  set("body2-title", pickText(item, "body2Title", "body2TitleEn") || "");
  set("body2-text", pickText(item, "body2", "body2En") || "");

  const imageEl = document.getElementById("detail-image-block");
  if (imageEl) imageEl.innerHTML = coverBlockHTML(item);

  const tagsEl = document.getElementById("detail-tags");
  const tags = pickTags(item);
  if (tagsEl && tags.length) {
    tagsEl.innerHTML =
      '<div class="tag-row">' +
      tags.map((t) => '<div class="tag">#' + t + "</div>").join("") +
      "</div>";
  }

  document.title = pickText(item, "title", "titleEn") + " — JUJUBE BOOKS";
}

function matchScrollbarGutter() {
  const probe = document.createElement("div");
  probe.style.cssText = "position:absolute; top:-9999px; left:-9999px; width:100px; height:100px; overflow:scroll;";
  document.body.appendChild(probe);
  const scrollbarWidth = probe.offsetWidth - probe.clientWidth;
  document.body.removeChild(probe);
  document.documentElement.style.setProperty("--scrollbar-w", scrollbarWidth + "px");
}

document.addEventListener("DOMContentLoaded", () => {
  initLangToggle();
  matchScrollbarGutter();
});

